public class PatternDemo {
    public static void main(String[] args) {
        int[] data = {4, 7, 2, 9, 1, 5};
        int sum = 0, count = 0, max = data[0];
        for (int val : data) {
            sum += val;           // accumulator
            if (val > 5) count++; // counter
            if (val > max) max = val; // max tracker
        }
        System.out.println("Sum:" + sum + " >5:" + count + " Max:" + max);
    }
}

public class ChooseDemo {
    public static void main(String[] args) {
        // FOR: known count
        for (int i = 0; i < 5; i++) { }
        // FOR-EACH: all elements
        int[] arr = {1,2,3};
        for (int n : arr) { }
        // WHILE: unknown count
        int x = 100;
        while (x > 1) { x /= 2; }
        // DO-WHILE: at least once
        do { System.out.print(""); } while (false);
    }
}

public class LoopBugs {
    public static void main(String[] args) {
        // BUG: semicolon after for
        for (int i = 0; i < 3; i++);
        {
            System.out.println("Only runs ONCE!");
        }
    }
}

