public class Search {
    public static void main(String[] args) {
        int[] nums = {7, 3, 9, 4, 11, 6};
        for (int n : nums) {
            if (n % 2 == 0) {
                System.out.println("First even: " + n);
                break;
            }
            System.out.println("Skipping odd: " + n);
        }
    }
}

public class SkipNeg {
    public static void main(String[] args) {
        int[] data = {5, -3, 8, -1, 0, 7, -4, 2};
        int sum = 0;
        for (int n : data) {
            if (n <= 0) continue;
            sum += n;
            System.out.println("Added " + n + ", sum=" + sum);
        }
    }
}

