public class SumAvg {
    public static void main(String[] args) {
        int[] scores = {85, 92, 78, 90, 88, 76, 95};
        int sum = 0;
        for (int s : scores) sum += s;
        double avg = (double) sum / scores.length;
        System.out.println("Sum: " + sum);
        System.out.printf("Average: %.1f%n", avg);
    }
}

public class Counter {
    public static void main(String[] args) {
        int[] temps = {18, 25, 32, 28, 15, 35, 22, 30};
        int hot = 0, cold = 0, nice = 0;
        for (int t : temps) {
            if (t >= 30) hot++;
            else if (t <= 18) cold++;
            else nice++;
        }
        System.out.println("Hot(>=30): " + hot);
        System.out.println("Cold(<=18): " + cold);
        System.out.println("Nice: " + nice);
    }
}

public class Countdown {
    public static void main(String[] args) {
        for (int i = 10; i >= 1; i--) {
            System.out.println(i + "...");
        }
        System.out.println("LAUNCH!");
    }
}

public class CharCount {
    public static void main(String[] args) {
        String text = "Hello World";
        int vowels = 0, consonants = 0;
        for (int i = 0; i < text.length(); i++) {
            char ch = Character.toLowerCase(text.charAt(i));
            if ("aeiou".indexOf(ch) >= 0) vowels++;
            else if (ch >= 'a' && ch <= 'z') consonants++;
        }
        System.out.println("Vowels: " + vowels + ", Consonants: " + consonants);
    }
}

public class Triangle {
    public static void main(String[] args) {
        int rows = 5;
        for (int i = 1; i <= rows; i++) {
            for (int j = 1; j <= i; j++) {
                System.out.print("* ");
            }
            System.out.println();
        }
    }
}

public class Validate {
    public static void main(String[] args) {
        int input = -1; // simulated first attempt
        int attempt = 0;
        do {
            attempt++;
            System.out.println("Attempt " + attempt + ": input = " + input);
            if (input < 1 || input > 10) {
                System.out.println("Invalid! Must be 1-10.");
                input = 7; // simulated retry
            }
        } while (input < 1 || input > 10);
        System.out.println("Accepted: " + input);
    }
}

public class DataProc {
    public static void main(String[] args) {
        int[] data = {23, 45, 12, 67, 34, 89, 5, 56};
        int sum=0, count=0, max=data[0], min=data[0];
        for (int val : data) {
            sum += val;
            count++;
            if (val > max) max = val;
            if (val < min) min = val;
        }
        System.out.println("Count: " + count);
        System.out.println("Sum: " + sum);
        System.out.printf("Avg: %.1f%n", (double)sum/count);
        System.out.println("Max: " + max + ", Min: " + min);
    }
}

